    graph_copy = graph_data.copy()
    domain_node = None
    for node in graph_copy.nodes(data=True):
        if node[1]['name'].startswith('ju1.a3.dom') and 'EK_CONTROL_DOMAIN' in node[1]['type']:
            domain_node = node[0]
            break

    child_nodes = []
    if domain_node:
        for neighbor in graph_copy.successors(domain_node):
            child_data = graph_copy.nodes[neighbor]
            if 'RK_CONTAINS' in graph_copy[domain_node][neighbor]['type']:
                capacity = 0
                if 'EK_PORT' in child_data['type']:
                    capacity = child_data.get('physical_capacity_bps', 0)
                else:
                    stack = [neighbor]
                    while stack:
                        current = stack.pop()
                        for succ in graph_copy.successors(current):
                            if 'RK_CONTAINS' in graph_copy[current][succ]['type']:
                                succ_data = graph_copy.nodes[succ]
                                if 'EK_PORT' in succ_data['type']:
                                    capacity += succ_data.get('physical_capacity_bps', 0)
                                else:
                                    stack.append(succ)
                child_nodes.append((child_data['name'], capacity))

    child_nodes.sort(key=lambda x: x[1], reverse=True)
    return_object = {
        'type': 'list',
        'data': child_nodes,
        'updated_graph': nx.readwrite.json_graph.node_link_data(graph_copy)
    }
    return return_object

